// function to convert LabJack AIN value to a decimal
function adc_to_float(ch) {

    let buffer = Buffer.alloc(4)
    buffer.writeUInt16BE(msg.payload[(ch * 2)], 0);
    buffer.writeUInt16BE(msg.payload[(ch * 2) + 1], 2);

//    let floatValue = buffer.readFloatBE(0).toFixed(2);
    let floatValue = buffer.readFloatBE(0);
    let result = 0;

    if(ch == 0) {   // Super Cap (No Voltage Divider)
        result = floatValue;
    } else if(ch == 6) {   // 3V3DC Voltage Divider
        result = floatValue / 0.760;
    } else {        // Everything Else
        result = floatValue / 0.338;
    }
    return result.toFixed(2);
}

